public int evaluate(String expr, Map<Character, Integer> priority) {
    Deque<Integer> nums = new ArrayDeque<>();
    Deque<Character> ops = new ArrayDeque<>();
    int i = 0;
    while (i < expr.length()) {
        char c = expr.charAt(i);
        if (Character.isDigit(c)) {
            int num = 0;
            while (i < expr.length() && Character.isDigit(expr.charAt(i)))
                num = num * 10 + (expr.charAt(i++) - '0');
            nums.push(num); continue;
        } else if (c == '(') { ops.push(c);
        } else if (c == ')') {
            while (ops.peek() != '(') applyOp(nums, ops);
            ops.pop();
        } else if (priority.containsKey(c)) {
            while (!ops.isEmpty() && ops.peek() != '('
                   && priority.getOrDefault(ops.peek(),-1) >= priority.get(c))
                applyOp(nums, ops);
            ops.push(c);
        }
        i++;
    }
    while (!ops.isEmpty()) applyOp(nums, ops);
    return nums.pop();
}

