public int[] twoSum(int[] nums, int target) {
    Map<Integer,Integer> seen = new HashMap<>();
    for (int i = 0; i < nums.length; i++) {
        int comp = target - nums[i];
        if (seen.containsKey(comp)) return new int[]{seen.get(comp), i};
        seen.put(nums[i], i);
    }
    return new int[]{-1,-1};
}

public boolean hasCycle(int V, List<List<Integer>> adj) {
    int[] color = new int[V];
    for (int i = 0; i < V; i++)
        if (color[i] == 0 && dfs(i, adj, color)) return true;
    return false;
}
private boolean dfs(int u, List<List<Integer>> adj, int[] c) {
    c[u] = 1;
    for (int v : adj.get(u)) {
        if (c[v] == 1) return true;
        if (c[v] == 0 && dfs(v, adj, c)) return true;
    }
    c[u] = 2; return false;
}

public class Account {
    private volatile double balance;
    private final ReentrantLock lock = new ReentrantLock();
    private final List<Transaction> history = new CopyOnWriteArrayList<>();
    public boolean debit(double amount) {
        lock.lock();
        try {
            if (balance < amount) return false;
            balance -= amount; return true;
        } finally { lock.unlock(); }
    }
}
// Transfer — lock ordering prevents deadlock
public boolean transfer(Account from, Account to, double amount) {
    Account first  = from.getId().compareTo(to.getId()) < 0 ? from : to;
    Account second = (first==from) ? to : from;
    first.getLock().lock();
    try {
        second.getLock().lock();
        try { return from.debit(amount) && (to.credit(amount) || true); }
        finally { second.getLock().unlock(); }
    } finally { first.getLock().unlock(); }
}

